patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 24a166906f1f..fd62fe965904 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1238,19 +1238,30 @@ static Instruction *foldAddToAshr(BinaryOperator &Add) {
   // sext (icmp ugt (X & (DivC - 1)), SMIN)
   const APInt *MaskC;
   ICmpInst::Predicate Pred;
+  Value *CmpRHS;
   if (!match(Add.getOperand(1),
              m_SExt(m_ICmp(Pred, m_And(m_Specific(X), m_APInt(MaskC)),
-                           m_SignMask()))) ||
-      Pred != ICmpInst::ICMP_UGT)
+                           m_Value(CmpRHS)))))
     return nullptr;

   APInt SMin = APInt::getSignedMinValue(Add.getType()->getScalarSizeInBits());
-  if (*MaskC != (SMin | (*DivC - 1)))
+  APInt ExpectedMask = SMin | (*DivC - 1);
+  if (*MaskC != ExpectedMask)
     return nullptr;

   // (X / DivC) + sext ((X & (SMin | (DivC - 1)) >u SMin) --> X >>s log2(DivC)
-  return BinaryOperator::CreateAShr(
-      X, ConstantInt::get(Add.getType(), DivC->exactLogBase2()));
+  if (Pred == ICmpInst::ICMP_UGT && match(CmpRHS, m_SignMask()))
+    return BinaryOperator::CreateAShr(
+        X, ConstantInt::get(Add.getType(), DivC->exactLogBase2()));
+
+  // (X / DivC) + sext ((X & (SMin | (DivC - 1)) == (SMin | (DivC - 1))) -->
+  // X >>s log2(DivC). This is only valid for DivC == 2, where DivC-1 == 1 and
+  // having the low bit set is equivalent to having any low bits set.
+  if (Pred == ICmpInst::ICMP_EQ && *DivC == 2 && match(CmpRHS, m_SpecificInt(ExpectedMask)))
+    return BinaryOperator::CreateAShr(
+        X, ConstantInt::get(Add.getType(), DivC->exactLogBase2()));
+
+  return nullptr;
 }

 Instruction *InstCombinerImpl::

